// ── Memory ring animation hook ─────────────────────────────────────────────

function copyInfo(label: string, value: string): void {
  const text = `${label} : ${value}`;
  navigator.clipboard.writeText(text);
  toast("info copied", "accent", { duration: 2000 });
}

function MemoryRing({ usedPct, memLabel }: { usedPct: number; memLabel: string }) {
  const ringRef = useRef<SVGPathElement>(null);
  const ringUnfilledRef = useRef<SVGPathElement>(null);
  const animRef = useRef<number>(0);

  useEffect(() => {
    const ring = ringRef.current;
    const ringUnfilled = ringUnfilledRef.current;
    if (!ring || !ringUnfilled) return;

    const CX = 50, CY = 50, R = 43, AMP = 3, FREQ = 20, N = 300, GAP = 4;
    const splitIdx = Math.floor(N * usedPct / 100);
    const filledStart = GAP;
    const filledEnd = Math.max(filledStart, Math.min(splitIdx - GAP, N - GAP));
    const unfilledStart = Math.max(splitIdx + GAP, GAP);
    const unfilledEnd = N - GAP;
    const uR = R + 2;

    function pt(i: number, rad: number): string {
      const theta = (i / N) * 2 * Math.PI;
      return `${(CX + rad * Math.cos(theta)).toFixed(1)} ${(CY + rad * Math.sin(theta)).toFixed(1)}`;
    }

    function buildFilled(phase: number): string {
      const pts: string[] = [];
      for (let i = filledStart; i <= filledEnd; i++) {
        const rad = R + AMP * 0.5 * (1 + Math.sin(phase + (i / N) * 2 * Math.PI * FREQ));
        pts.push(`${i === filledStart ? "M" : "L"}${pt(i, rad)}`);
      }
      return pts.join("");
    }

    const uPts: string[] = [];
    for (let i = unfilledStart; i <= unfilledEnd; i++) {
      uPts.push(`${i === unfilledStart ? "M" : "L"}${pt(i, uR)}`);
    }
    ringUnfilled.setAttribute("d", uPts.join(""));

    let prevPhase = -1;
    function tick(t: number) {
      if (!ring || !ring.isConnected) return;
      const phase = (t / 1000) * 2.5;
      if (Math.abs(phase - prevPhase) > 0.02) {
        ring.setAttribute("d", buildFilled(phase));
        prevPhase = phase;
      }
      animRef.current = requestAnimationFrame(tick);
    }
    animRef.current = requestAnimationFrame(tick);

    return () => cancelAnimationFrame(animRef.current);
  }, [usedPct]);

  return (
    <div className="metric-tile-m3 mem-card col-span-2" style={{ cursor: "pointer" }} onClick={() => copyInfo("MEMORY", `${usedPct}% (${memLabel})`)}>
      <div className="mem-card-header">
        <div className="metric-icon-badge" dangerouslySetInnerHTML={{ __html: SVG_RAM }} />
        <span className="metric-label mem-label">MEMORY</span>
      </div>
      <div className="mem-container">
        <svg className="mem-bg-ring" viewBox="0 0 100 100">
          <path ref={ringUnfilledRef} fill="none" stroke="var(--md-sys-color-outline-variant)" strokeWidth="7" strokeLinecap="round" strokeLinejoin="round" />
          <path ref={ringRef} fill="none" stroke="var(--md-sys-color-primary)" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
        <div className="mem-overlay">
          <div className="mem-pct">{usedPct}%</div>
          <div className="mem-avail">{memLabel}</div>
        </div>
      </div>
    </div>
  );
}

// ── Security Calendar display ──────────────────────────────────────────────

function SecurityCalendar({ patch }: { patch: string }) {
  let dayStr = "—", monthWeekdayStr = "— —", yearStr = "—";
  if (patch && patch !== "—") {
    const parts = patch.split("-");
    if (parts.length === 3) {
      const year = parts[0], month = parseInt(parts[1], 10) - 1, day = parseInt(parts[2], 10);
      const d = new Date(Date.UTC(parseInt(year, 10), month, day));
      const months = ["JAN","FEB","MAR","APR","MAY","JUN","JUL","AUG","SEP","OCT","NOV","DEC"];
      const days = ["SUN","MON","TUE","WED","THU","FRI","SAT"];
      dayStr = String(day).padStart(2, "0");
      monthWeekdayStr = `${months[month] || "—"} ${days[d.getUTCDay()] || "—"}`;
      yearStr = year;
    }
  }
  return (
    <div className="security-calendar-display">
      <span className="sec-day">{dayStr}</span>
      <span className="sec-month-weekday">{monthWeekdayStr}</span>
      <span className="sec-year">{yearStr}</span>
    </div>
  );
}

// ── Metric tile ────────────────────────────────────────────────────────────

function MetricTile({
  icon, label, value, className = "",
  children,
}: {
  icon: string; label: string; value?: string; className?: string;
  children?: React.ReactNode;
}) {
  const handleClick = () => {
    if (value && value !== "—") copyInfo(label, value);
  };

  return (
    <div
      className={`metric-tile-m3 ${className}`}
      onClick={handleClick}
      style={{ cursor: value && value !== "—" ? "pointer" : undefined }}
    >
      <div className="metric-icon-badge" dangerouslySetInnerHTML={{ __html: icon }} />
      <div className="metric-details">
        <span className="metric-label">{label}</span>
        {value !== undefined && <span className="metric-value">{value || "—"}</span>}
        {children}
      </div>
    </div>
  );
}

